using System.ComponentModel;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

namespace McpServer.Tools;

[McpServerToolType]
public sealed class ExternalApiTool
{
    [McpServerTool, Description("Fetches data from an external API for the given resource path.")]
    public static async Task<string> FetchData(
        IHttpClientFactory httpClientFactory,
        ILogger<ExternalApiTool> logger,
        [Description("The API resource path to fetch (e.g. \"users/1\")")] string path,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching external API resource: {Path}", path);

        using var client = httpClientFactory.CreateClient("ExternalApi");

        var response = await client.GetAsync(path, cancellationToken);
        response.EnsureSuccessStatusCode();

        var content = await response.Content.ReadAsStringAsync(cancellationToken);

        logger.LogInformation("Successfully fetched {Length} chars from {Path}", content.Length, path);
        return content;
    }
}

